[Fact]
public async Task SelectTaskWithPriorRun_LoadsStageStatusesFromDisk()
{
    using var repo = TestRepository.Create();
    repo.WriteConfig("dotnet test", []);
    repo.WriteTask("alpha", "# Alpha\n");
    var statusDir = Path.Combine(repo.Root, ".relay", "alpha");
    Directory.CreateDirectory(statusDir);
    var statusEntries = new[]
    {
        new StageStatusEntry(1, "Ideate", "Done", DurationSeconds: 42.5, CostUsd: 0.15, Turns: 12, Model: "test-model"),
        new StageStatusEntry(2, "Research", "Flagged", Error: "something went wrong"),
    };
    await StageStatusRecord.WriteAsync(statusDir, statusEntries);

    var viewModel = new MainWindowViewModel { RootPath = repo.Root };
    await viewModel.LoadInitialAsync();
    await viewModel.LastSelectionLoad!;

    Assert.Equal("Done", viewModel.Stages[0].Status);
    Assert.Equal("42s", viewModel.Stages[0].DurationLabel);
    Assert.Equal("$0.15", viewModel.Stages[0].CostLabel);
    Assert.Equal("12t", viewModel.Stages[0].TurnsLabel);
    Assert.Equal("test-model", viewModel.Stages[0].ModelLabel);
    Assert.Equal("Flagged", viewModel.Stages[1].Status);
    // Stage 3 was not in status.json — stays Waiting after ResetStages() + empty metric.
    Assert.Equal("Waiting", viewModel.Stages[2].Status);
}

[Fact]
public async Task RestartClearsStageBoard_DoesNotLoadStaleStatusFromDisk()
{
    using var repo = TestRepository.Create();
    repo.WriteConfig("dotnet test", []);
    repo.WriteTask("alpha", "# Alpha\n");
    var statusDir = Path.Combine(repo.Root, ".relay", "alpha");
    Directory.CreateDirectory(statusDir);
    var statusEntries = new[]
    {
        new StageStatusEntry(1, "Ideate", "Done"),
        new StageStatusEntry(2, "Research", "Done"),
    };
    await StageStatusRecord.WriteAsync(statusDir, statusEntries);

    var viewModel = new MainWindowViewModel { RootPath = repo.Root };
    await viewModel.LoadInitialAsync();
    await viewModel.LastSelectionLoad!;

    // Selecting the task loads status from disk → Done stages.
    Assert.Equal("Done", viewModel.Stages[0].Status);
    Assert.Equal("Done", viewModel.Stages[1].Status);
    Assert.Equal("Waiting", viewModel.Stages[2].Status);

    // Deselect: SelectedTask = null triggers ResetStages() (no-arg, clear-only).
    viewModel.SelectedTask = null;
    await viewModel.LastSelectionLoad!;
    Assert.All(viewModel.Stages, stage => Assert.Equal("Waiting", stage.Status));

    // Re-select: must reload from disk (not show stale Waiting).
    viewModel.SelectedTask = viewModel.Tasks[0];
    await viewModel.LastSelectionLoad!;
    Assert.Equal("Done", viewModel.Stages[0].Status);
    Assert.Equal("Done", viewModel.Stages[1].Status);
    Assert.Equal("Waiting", viewModel.Stages[2].Status);
}

